import{_ as i}from"./plugin-vue_export-helper-c27b6911.js";import{r as l,o as d,c as t,a as e,b as a,e as r,d as s}from"./app-802747a1.js";const c={},o=s(`<h1 id="git仓库操作" tabindex="-1"><a class="header-anchor" href="#git仓库操作" aria-hidden="true">#</a> GIT仓库操作</h1><h2 id="仓库配置信息" tabindex="-1"><a class="header-anchor" href="#仓库配置信息" aria-hidden="true">#</a> 仓库配置信息</h2><h3 id="查看配置信息" tabindex="-1"><a class="header-anchor" href="#查看配置信息" aria-hidden="true">#</a> 查看配置信息</h3><p>config 配置有system(系统级别)、global(用户级别)和local(当前仓库)，三个设置优先级: <code>system -&gt; global -&gt;local</code>​ ,底层配置会覆盖顶层配置, 分别使用<code>--system/global/local</code>​ 定位到配置文件</p><p>查看系统config</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">git</span> config <span class="token parameter variable">--system</span> <span class="token parameter variable">--list</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>查看当前用户（global）配置</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">git</span> config <span class="token parameter variable">--global</span>  <span class="token parameter variable">--list</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>查看当前仓库配置信息</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">git</span> config <span class="token parameter variable">--local</span>  <span class="token parameter variable">--list</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="设置配置信息" tabindex="-1"><a class="header-anchor" href="#设置配置信息" aria-hidden="true">#</a> 设置配置信息</h3><p>设置全局身份信息</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">git</span> config <span class="token parameter variable">--global</span> user.name <span class="token string">&#39;test&#39;</span>
<span class="token function">git</span> config <span class="token parameter variable">--global</span> user.email <span class="token string">&#39;test@qq.com&#39;</span>
<span class="token comment"># git config --global user.password &#39;test&#39;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在仓库下设置局部身份信息</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">git</span> config user.name <span class="token string">&#39;test&#39;</span>
<span class="token function">git</span> config user.email <span class="token string">&#39;test@qq.com&#39;</span>
<span class="token comment"># git config user.password &#39;test&#39;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="取消配置信息" tabindex="-1"><a class="header-anchor" href="#取消配置信息" aria-hidden="true">#</a> 取消配置信息</h3><p>取消全局身份信息</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">git</span> config <span class="token parameter variable">--unset</span> <span class="token parameter variable">--global</span> user.name
<span class="token function">git</span> config <span class="token parameter variable">--unset</span> <span class="token parameter variable">--global</span> user.email
<span class="token comment"># git config --unset --global user.password</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在仓库下取消局部身份信息</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">git</span> config <span class="token parameter variable">--unset</span> <span class="token parameter variable">--local</span> user.name
<span class="token function">git</span> config <span class="token parameter variable">--unset</span> <span class="token parameter variable">--local</span> user.email
<span class="token comment"># git config --unset --local user.password</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="仓库密钥管理" tabindex="-1"><a class="header-anchor" href="#仓库密钥管理" aria-hidden="true">#</a> 仓库密钥管理</h2><p>git使用https协议，每次pull, push都要输入密码，相当的麻烦。这个时候就可以使用ssh密钥进行身份认证，这样可以省去每次都输密码。</p><h3 id="本地密钥生成" tabindex="-1"><a class="header-anchor" href="#本地密钥生成" aria-hidden="true">#</a> 本地密钥生成</h3><h4 id="创建密钥" tabindex="-1"><a class="header-anchor" href="#创建密钥" aria-hidden="true">#</a> 创建密钥</h4><p>终端输入命令</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>ssh-keygen <span class="token parameter variable">-t</span> rsa <span class="token parameter variable">-C</span> <span class="token string">&quot;your@email.com&quot;</span>（请填你设置的邮箱地址）
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>接着出现：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>Generating public/private rsa key pair.

Enter <span class="token function">file</span> <span class="token keyword">in</span> <span class="token function">which</span> to save the key <span class="token punctuation">(</span>/Users/your_user_directory/.ssh/id_rsa<span class="token punctuation">)</span>:
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>请直接按下回车</p><p>然后系统会自动在<code>.ssh</code>文件夹下生成两个文件，<code>id_rsa</code>和<code>id_rsa.pub</code>，用记事本打开<code>id_rsa.pub</code></p><p>将全部的内容复制</p><h3 id="远程仓库密钥配置" tabindex="-1"><a class="header-anchor" href="#远程仓库密钥配置" aria-hidden="true">#</a> 远程仓库密钥配置</h3><h4 id="github密钥配置" tabindex="-1"><a class="header-anchor" href="#github密钥配置" aria-hidden="true">#</a> GitHub密钥配置</h4><h5 id="添加公钥" tabindex="-1"><a class="header-anchor" href="#添加公钥" aria-hidden="true">#</a> 添加公钥</h5>`,34),p={href:"https://github.com/",target:"_blank",rel:"noopener noreferrer"},u=s(`<p>进入ssh设置</p><p>点击 <code>New SSH key</code></p><p>在key中将刚刚复制的粘贴进去</p><p>最后点击<code>Add SSH key</code></p><h5 id="测试" tabindex="-1"><a class="header-anchor" href="#测试" aria-hidden="true">#</a> 测试</h5><p>在终端输入</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">ssh</span> <span class="token parameter variable">-T</span> git@github.com
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>你将会看到：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>The authenticity of <span class="token function">host</span> <span class="token string">&#39;github.com (207.97.227.239)&#39;</span> can&#39;t be established.
RSA key fingerprint is <span class="token number">16</span>:27:ac:a5:76:28:2d:36:63:1b:56:4d:eb:df:a6:48.
Are you sure you want to <span class="token builtin class-name">continue</span> connecting <span class="token punctuation">(</span>yes/no<span class="token punctuation">)</span>?
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>输入 yes</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>Hi humingx<span class="token operator">!</span> You&#39;ve successfully authenticated, but GitHub does not provide shell access.
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>如果看到Hi后面是你的用户名，就说明成功了。</p><h4 id="gitee仓库密钥配置" tabindex="-1"><a class="header-anchor" href="#gitee仓库密钥配置" aria-hidden="true">#</a> Gitee仓库密钥配置</h4><blockquote><p>Gitee仓库密钥配置和GitHub密钥配置步骤相似</p></blockquote><h4 id="gitlab仓库密钥配置" tabindex="-1"><a class="header-anchor" href="#gitlab仓库密钥配置" aria-hidden="true">#</a> Gitlab仓库密钥配置</h4><blockquote><p>Gitlab仓库密钥配置和GitHub密钥配置步骤相似</p></blockquote><h2 id="错误解析" tabindex="-1"><a class="header-anchor" href="#错误解析" aria-hidden="true">#</a> 错误解析</h2><h3 id="密钥未配置" tabindex="-1"><a class="header-anchor" href="#密钥未配置" aria-hidden="true">#</a> 密钥未配置</h3><ul><li>错误原因：</li></ul><p>当使用git方式下载时，如果没有配置过<code>ssh key</code>，则会有如下错误提示：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>git@github.com:Permissiondenied<span class="token punctuation">(</span>publickey<span class="token punctuation">)</span> 
fatal: Could not <span class="token builtin class-name">read</span> from remote repository
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>解决方案：</li></ul><p>正常配置<code>ssh</code>密钥即可。</p><h3 id="密钥不匹配" tabindex="-1"><a class="header-anchor" href="#密钥不匹配" aria-hidden="true">#</a> 密钥不匹配</h3><blockquote><p>重装系统之后,git push的时候会出现问题:<code>The authenticity of host &#39;github.com (13.229.188.59)&#39; can&#39;t be established.</code></p></blockquote><ul><li>错误原因：</li></ul><p>本地仓库和远程的SSH密钥不匹配</p><ul><li>解决办法：</li></ul><p>重新配置仓库密钥即可</p><h3 id="免密登录失败" tabindex="-1"><a class="header-anchor" href="#免密登录失败" aria-hidden="true">#</a> 免密登录失败</h3><blockquote><p>在本地电脑上已经配置过 密钥，但是每次上传、下载仍然需要输入用户名和密码</p></blockquote><ul><li>错误原因</li></ul><p>首先来明确一下需要每次输入用户名和密码的场景：</p><p>首先，必须是使用<code>https</code>方式下载的代码在操作时才可能需要输入用户名密码。</p><p>第二，在满足第一点的基础上，未配置<code>credential.helper</code>。可以用如下命令检查<code>credential.helper</code>的当前配置：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">git</span> config <span class="token parameter variable">-l</span> <span class="token operator">|</span> <span class="token function">grep</span> credential.helper
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>如果未配置的话结果应该为空。</p><ul><li>解决方案：</li></ul><p>方案一, 既然是因为本地仓库和远程仓库关联时使用 <code>ssh</code>方式，才会没有使用密钥验证身份，而是重复输入密码验证。因此，可以删除<code>https</code>方式的本地仓库的远程连接，然后添加<code>ssh</code>方式的远程链接</p><p>方案二, 既然是因为未配置<code>credential.helper</code>。简单粗暴的办法就是直接配置<code>credential.helper</code>的值为<code>manager</code></p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">git</span> config  <span class="token parameter variable">--global</span> credential.helper manager
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>再次尝试<code>pull</code>代码的时候会弹出窗口要求输入用户名密码（只需要输入这一次就ok了）。</p>`,42);function h(b,g){const n=l("ExternalLinkIcon");return d(),t("div",null,[o,e("p",null,[a("打开"),e("a",p,[a("https://github.com/"),r(n)]),a("，登陆你的账户，进入设置")]),u])}const k=i(c,[["render",h],["__file","GIT仓库操作.html.vue"]]);export{k as default};
